# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit

class AppDelegate: NSObject, UIApplicationDelegate {

    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        // Override point for customization after application launch.
        return true
    }

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        guard let components = NSURLComponents(url: url, resolvingAgainstBaseURL: false),
            let queryItems = components.queryItems else { return false }

        var promoCode: String?
        var discountPercentage: Int?

        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value
            case "discount":
                discountPercentage = Int(item.value ?? "")
            default:
                break
            }
        }

        if let promoCode = promoCode, let discountPercentage = discountPercentage {
            // Apply promo code and discount percentage to user accounts
            print("Promo code is \(promoCode) with discount of \(discountPercentage)%")
        } else {
            print("No promo code or discount percentage found in URL parameters")
        }

        return true
    }
}